// Normalize input payload from Webhook, Telegram, or Google Sheet schedule.
let source;
let triggered_by = 'schedule';

function clean(value) {
  return String(value ?? '').trim();
}

function slugify(value) {
  return clean(value)
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

try {
  source = $('Trigger: Webhook').first().json.body || {};
  triggered_by = 'webhook';
} catch (e) {
  const rows = $('Sheet: Get Pending Keyword').all().map(item => item.json || {});
  const blockedStatuses = new Set(['completed', 'done', 'published', 'processing', 'running', 'skip', 'skipped', 'failed', 'error']);
  source = rows.find(row => {
    const keyword = clean(row.keyword);
    const status = clean(row.status).toLowerCase();
    return keyword && !blockedStatuses.has(status);
  });

  if (!source) {
    return [];
  }
}

const sourcePayload = source && typeof source === 'object'
  ? JSON.parse(JSON.stringify(source))
  : {};

function firstValue(...values) {
  return values.find(value => value !== undefined && value !== null && clean(value) !== '');
}

const sourceProductPayload = {
  asin_code: clean(firstValue(source.asin_code, source.asin, source.ASIN)),
  asin_title: clean(firstValue(source.asin_title, source.title, source.product_title)),
  asin_brand: clean(firstValue(source.asin_brand, source.brand)),
  asin_category: clean(firstValue(source.asin_category, source.category_name, source.category)),
  asin_price: clean(firstValue(source.asin_price, source.price)),
  asin_rating: clean(firstValue(source.asin_rating, source.rating)),
  asin_reviews_count: source.asin_reviews_count ?? source.reviews_count ?? source.review_count ?? 0,
  asin_description: clean(firstValue(source.asin_description, source.description)),
  asin_features: source.asin_features || source.features || '',
  asin_specifications: Array.isArray(source.asin_specifications) ? source.asin_specifications : [],
  asin_top_reviews: Array.isArray(source.asin_top_reviews) ? source.asin_top_reviews : []
};

const sourceArticlePayload = {
  post_id: source.post_id || source.postId || source.id || '',
  keyword: clean(firstValue(source.keyword, source.article_keyword, source.focus_keyword)),
  category_name: clean(firstValue(source.category_name, source.category)),
  products_count: source.products_count ?? source.asin_count ?? source.count ?? '',
  products: source.products || '',
  related_posts: source.related_posts || '',
  existing_title: source.existing_title || source.title || '',
  existing_content: source.existing_content || source.content || '',
  price_range: source.price_range || '',
  price_min: source.price_min || '',
  price_max: source.price_max || '',
  brand_list: source.brand_list || '',
  review_count: source.review_count || '',
  review_count_formatted: source.review_count_formatted || '',
  shortcode_list: source.shortcode_list || '',
  shortcode_grid: source.shortcode_grid || '',
  shortcode_card: source.shortcode_card || ''
};

const keyword = clean(firstValue(
  source.keyword,
  source.article_keyword,
  source.parent_keyword,
  source.focus_keyword,
  source.existing_title,
  source.asin_title,
  source.title
));
if (!keyword) {
  if (triggered_by === 'schedule') {
    return [];
  }
  throw new Error('Pipeline Error: No keyword found in input payload.');
}

function parseAsinList(value) {
  if (!value) return [];
  const raw = Array.isArray(value)
    ? value
    : (String(value).match(/B[0-9A-Z]{9}/gi) || String(value).split(/[ ,\n]+/));
  const seen = new Set();
  return raw
    .map(a => clean(a).toUpperCase())
    .filter(a => /^B[0-9A-Z]{9}$/.test(a))
    .filter(a => {
      if (seen.has(a)) return false;
      seen.add(a);
      return true;
    });
}

const categories = [
  'Standing Desks',
  'Ergonomic Chairs',
  'Desk Converters',
  'Desk Storage',
  'Footrests & Mats',
  'Monitor Arms',
  'Desk Lighting',
  'Cable Management',
  'Keyboards & Mice',
  'Desk Accessories',
  'Ergonomics & Health',
  'Workspace Ideas',
  'Productivity'
];

function normalizeCategory(value) {
  const input = clean(value).toLowerCase();
  if (!input) return '';
  return categories.find(category => category.toLowerCase() === input) || '';
}

function inferCategory(value) {
  const text = clean(value).toLowerCase();
  const rules = [
    ['Standing Desks', ['standing desk', 'sit stand', 'sit-stand', 'height adjustable desk', 'electric desk']],
    ['Ergonomic Chairs', ['ergonomic chair', 'office chair', 'desk chair', 'computer chair', 'chair']],
    ['Desk Converters', ['desk converter', 'standing desk converter', 'desk riser', 'sit stand converter']],
    ['Desk Storage', ['desk storage', 'file cabinet', 'drawer', 'shelf', 'cabinet', 'organizer']],
    ['Footrests & Mats', ['footrest', 'foot rest', 'anti fatigue', 'standing mat', 'desk mat']],
    ['Monitor Arms', ['monitor arm', 'monitor mount', 'dual monitor', 'monitor stand']],
    ['Desk Lighting', ['desk lamp', 'lamp', 'light', 'lighting', 'zoom meeting', 'video light', 'soft light']],
    ['Cable Management', ['cable', 'cord', 'wire management', 'cable tray']],
    ['Keyboards & Mice', ['keyboard', 'mouse', 'mice', 'trackball']],
    ['Ergonomics & Health', ['posture', 'back pain', 'wrist rest', 'ergonomic setup', 'health']],
    ['Workspace Ideas', ['workspace idea', 'home office idea', 'office setup', 'small space', 'layout', 'decor']],
    ['Productivity', ['productivity', 'focus', 'workflow', 'time management']]
  ];

  for (const [category, needles] of rules) {
    if (needles.some(needle => text.includes(needle))) {
      return category;
    }
  }

  return 'Desk Accessories';
}

const asins = parseAsinList(firstValue(source.asins, source.asin_list, source.article_asins, source.asin_code, source.asin, source.shortcode_list, source.shortcode_grid, source.shortcode_card, source.products));
const rawCategory = normalizeCategory(firstValue(source.category, source.category_name, source.asin_category));
const category = rawCategory || inferCategory(keyword);
const category_inferred = !rawCategory;
const rawAsinCount = source.asin_count ?? source.asinCount ?? source.products_count ?? source.productsCount ?? source.max_asins ?? source.maxAsins ?? source.limit ?? source.count;
const parsedAsinCount = parseInt(rawAsinCount, 10);
const asin_count = Math.max(1, Math.min(
  Number.isFinite(parsedAsinCount) ? parsedAsinCount : (asins.length || 8),
  15
));
const keyword_queue_id = clean(source.keyword_queue_id || source.keywordQueueId || source.queue_id || source.queueId || source.row_id || source.rowId || source.row_number || source.row_index || '');
const providedRequestId = clean(source.request_id || source.requestId);
const providedRunId = clean(source.job_group_id || source.jobGroupId || source.run_id || source.runId || providedRequestId);
const job_started_at = new Date().toISOString();
const job_group_id = providedRunId || [slugify(keyword), job_started_at.replace(/[-:.TZ]/g, '').slice(0, 14)].filter(Boolean).join('-');

let author_id = 7;
let author_name = 'Morgan Davis';
let author_persona = 'Product Review Editor focusing on practical buying guides, honest trade-off summaries, editorial standards, and definitive verdicts to help buyers make better decisions.';

const alexCategories = ['Standing Desks', 'Desk Converters', 'Monitor Arms', 'Cable Management', 'Keyboards & Mice'];
const jordanCategories = ['Ergonomic Chairs', 'Desk Storage', 'Footrests & Mats', 'Desk Lighting', 'Desk Accessories', 'Ergonomics & Health', 'Workspace Ideas', 'Productivity'];

if (alexCategories.includes(category)) {
  author_id = 5;
  author_name = 'Alex Carter';
  author_persona = 'Research Lead focusing on product research, deep technical specs, dimensions, weight capacity, frame design, and rigorous hardware comparisons.';
} else if (jordanCategories.includes(category)) {
  author_id = 6;
  author_name = 'Jordan Lee';
  author_persona = 'Workspace Editor focusing on real-world home office fit, ergonomics, room dimensions, cable clutter, aesthetics, and daily routine impact in small spaces.';
}

return [{
  json: {
    keyword,
    category,
    category_inferred,
    category_name: sourceArticlePayload.category_name || category,
    queue_payload_type: sourceProductPayload.asin_code ? 'asin_product' : (sourceArticlePayload.post_id || sourceArticlePayload.products ? 'article' : 'keyword'),
    source_payload: sourcePayload,
    source_product_payload: sourceProductPayload,
    source_article_payload: sourceArticlePayload,
    post_id: sourceArticlePayload.post_id,
    existing_title: sourceArticlePayload.existing_title,
    existing_content: sourceArticlePayload.existing_content,
    related_posts: sourceArticlePayload.related_posts,
    products: sourceArticlePayload.products,
    asins,
    asin_count,
    job_group_id,
    run_id: job_group_id,
    keyword_queue_id,
    parent_keyword: keyword,
    article_keyword: keyword,
    job_started_at,
    row_index: source.row_index || source.row_number || null,
    sheet_status: clean(source.status),
    triggered_by,
    notify_channel: source.notify_channel || source.notifyChannel || '',
    chat_id: source.chat_id || source.chatId || source.telegram_chat_id || source.telegramChatId || '',
    telegram_chat_id: source.telegram_chat_id || source.telegramChatId || source.chat_id || source.chatId || '',
    telegram_message_id: source.telegram_message_id || source.telegramMessageId || '',
    request_id: providedRequestId || job_group_id,
    requested_by: source.requested_by || source.requestedBy || '',
    notes: clean(source.notes),
    source: source.source || triggered_by,
    author_id,
    author_name,
    author_persona
  }
}];

const input = $('Normalize Input').first().json;
const requestedLimit = Math.max(1, Math.min(parseInt(input.asin_count, 10) || 8, 15));
const scrapeLimit = input.asins && input.asins.length > 0
  ? requestedLimit
  : Math.max(requestedLimit, Math.min(15, requestedLimit + 5));
const limit = requestedLimit;

function uniqueValidAsins(values) {
  const seen = new Set();
  return values
    .map(a => String(a || '').trim().toUpperCase())
    .filter(a => /^B[0-9A-Z]{9}$/.test(a))
    .filter(a => {
      if (seen.has(a)) return false;
      seen.add(a);
      return true;
    });
}

function fatalAsinSearchError(message, extra = {}) {
  return [{
    json: {
      ...input,
      asins: [],
      asin_count: limit,
      asins_source: 'crawbase_search_failed',
      _fatal_error: true,
      _fatal_node: 'Parse ASINs',
      _fatal_stage: 'asin_search',
      _fatal_message: String(message || 'ASIN search failed'),
      _fatal_extra: extra,
      _fatal_action: 'Provide ASINs manually, simplify the keyword, or check Crawbase structured Amazon search.'
    }
  }];
}

if (input.asins && input.asins.length > 0) {
  const asins = uniqueValidAsins(input.asins).slice(0, limit);
  if (!asins.length) {
    return fatalAsinSearchError('No valid ASINs provided in input payload.');
  }
  return [{ json: { ...input, asins, asin_count: limit, asins_source: 'provided' } }];
}

function parseBody(data) {
  const rawBody = typeof data === 'string' ? data : (data.body ?? data.data ?? data.message ?? '');

  if (typeof rawBody === 'string' && /<!doctype html|<html/i.test(rawBody)) {
    return { parsed: null, rawBody, html: true };
  }

  let parsed = data;
  if (typeof rawBody === 'string' && rawBody.trim().startsWith('{')) {
    try {
      parsed = JSON.parse(rawBody);
    } catch (error) {
      parsed = data;
    }
  }

  return { parsed, rawBody, html: false };
}

const pageInputs = $input.all().map(item => item.json || {});
const parsedPages = pageInputs.map(parseBody);

if (parsedPages.some(page => page.html) && !parsedPages.some(page => page.parsed && typeof page.parsed === 'object')) {
  return fatalAsinSearchError('Crawbase search returned Amazon HTML instead of structured JSON. Check Crawlbase scraper=amazon-serp, token type, and query.', {
    search_query: $('Setup Global Config').first().json.search_query || input.keyword
  });
}

const resultBuckets = [
  'results',
  'organic_results',
  'search_results',
  'products',
  'ads',
  'amazons_choice',
  'sponsored_results'
];

function unwrapStructured(value) {
  if (!value) return {};
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim().startsWith('{')) {
    try { return JSON.parse(value); } catch (e) { return {}; }
  }
  if (typeof value !== 'object') return {};
  if (value.body && typeof value.body === 'object') return value.body;
  if (value.data && typeof value.data === 'object') return value.data;
  if (typeof value.body === 'string' && value.body.trim().startsWith('{')) {
    try { return JSON.parse(value.body); } catch (e) {}
  }
  if (typeof value.data === 'string' && value.data.trim().startsWith('{')) {
    try { return JSON.parse(value.data); } catch (e) {}
  }
  return value;
}

const results = parsedPages.flatMap(page => {
  const parsed = unwrapStructured(page.parsed || {});
  if (Array.isArray(parsed)) return parsed;
  return resultBuckets.flatMap(key => Array.isArray(parsed[key]) ? parsed[key] : []);
});

function asinFromRecord(record) {
  const direct = record.asin || record.asin_number || record.parent_asin || record.product_asin || record.asin_id;
  if (direct) return direct;

  const url = String(record.url || record.link || record.product_url || '');
  const match = url.match(/(?:\/dp\/|\/gp\/product\/|[?&](?:asin|creativeASIN)=)(B[0-9A-Z]{9})/i);
  return match ? match[1] : '';
}

const searchQuery = ($('Setup Global Config').first().json.search_query || input.keyword || '').toLowerCase();
const stopWords = new Set(['best', 'top', 'cheap', 'review', 'reviews', 'for', 'with', 'and', 'home', 'office']);
const words = searchQuery.split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w));

const records = results
  .map(record => ({ record, asin: asinFromRecord(record) }))
  .filter(item => item.asin);

const filteredRecords = records.filter(({ record }) => {
  const name = String(record.name || record.title || '').toLowerCase();
  return words.length === 0 || words.some(word => name.includes(word));
});

const filteredAsins = uniqueValidAsins(filteredRecords.map(item => item.asin));
const allAsins = uniqueValidAsins(records.map(item => item.asin));
const sourceAsins = filteredAsins.concat(allAsins.filter(asin => !filteredAsins.includes(asin)));
const asins = sourceAsins.slice(0, scrapeLimit);

if (asins.length === 0) {
  const keys = Array.from(new Set(parsedPages.flatMap(page => Object.keys(page.parsed || {})))).slice(0, 12).join(', ');
  return fatalAsinSearchError('No relevant ASINs found for: ' + input.keyword, {
    search_query: $('Setup Global Config').first().json.search_query || input.keyword,
    crawbase_keys: keys,
    pages_checked: String(pageInputs.length)
  });
}

if (asins.length < requestedLimit) {
  return fatalAsinSearchError('Only found ' + asins.length + ' ASINs, but asin_count requested ' + requestedLimit + '.', {
    search_query: $('Setup Global Config').first().json.search_query || input.keyword,
    found_asin_count: String(asins.length),
    requested_asin_count: String(requestedLimit),
    pages_checked: String(pageInputs.length),
    search_result_records: String(records.length),
    search_filtered_records: String(filteredRecords.length)
  });
}

return [{
  json: {
    ...input,
    asins,
    asin_count: requestedLimit,
    scrape_target_count: scrapeLimit,
    asins_source: 'crawbase_search',
    found_asin_count: asins.length,
    search_pages_checked: pageInputs.length,
    search_result_records: records.length,
    search_filtered_records: filteredRecords.length
  }
}];

const normalize = $('Normalize Input').first().json || {};
const keyword = normalize.keyword;
const category = normalize.category;
const splitAsins = $('Split ASINs').all();
const asinList = splitAsins.map(item => item.json?.asins).filter(Boolean);
const asinListString = asinList.join(',');

function clean(value) {
  return String(value ?? '')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function decodeHtml(value) {
  return clean(value)
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#34;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>');
}

function stripTags(value) {
  return decodeHtml(String(value || '').replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' '));
}

function firstValue(...values) {
  return values.find(value => value !== undefined && value !== null && clean(value) !== '');
}

function compactText(value, max = 4000) {
  const text = clean(value);
  return text.length > max ? text.slice(0, max).replace(/\s+\S*$/, '').trim() : text;
}

function specName(key) {
  return clean(key).replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
}

function specValue(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') return clean(value);
  if (Array.isArray(value)) return value.map(specValue).filter(Boolean).join(', ');
  if (typeof value === 'object') {
    if (value.stars || value.count) return [value.stars, value.count].filter(Boolean).join(' ');
    return '';
  }
  return clean(value);
}

function specsFromProductInformation(productInformation) {
  if (!productInformation || typeof productInformation !== 'object') return [];
  return Object.entries(productInformation)
    .map(([key, value]) => ({ name: specName(key), value: specValue(value) }))
    .filter(entry => entry.name && entry.value)
    .slice(0, 80);
}

function specsFromSource(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map(entry => ({
      name: clean(entry?.name || entry?.label || entry?.key),
      value: clean(entry?.value)
    }))
    .filter(entry => entry.name && entry.value)
    .slice(0, 80);
}

function featureArray(value) {
  if (Array.isArray(value)) return value.map(clean).filter(Boolean);
  return String(value || '')
    .split(/\n+/)
    .map(line => clean(line.replace(/^[-*]\s*/, '')))
    .filter(Boolean);
}

function reviewArray(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map(review => ({
      title: clean(review.title || review.review_title || ''),
      rating: clean(review.rating || review.stars || ''),
      author: clean(review.author || review.profile_name || ''),
      date: clean(review.date || review.review_date || ''),
      review: compactText(review.review || review.text || review.content || '', 1200)
    }))
    .filter(review => review.review)
    .slice(0, 5);
}

function reviewString(reviews) {
  return reviews
    .map(review => [review.title, review.rating, review.review].filter(Boolean).join('\n'))
    .join('\n---\n');
}

function matchFirst(text, patterns) {
  for (const pattern of patterns) {
    const match = String(text || '').match(pattern);
    if (match && match[1]) return decodeHtml(match[1]);
  }
  return '';
}

function parseCrawbaseHtml(html, asin) {
  const title = matchFirst(html, [
    /<span[^>]+id=["']productTitle["'][^>]*>([\s\S]*?)<\/span>/i,
    /<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']+)["']/i,
    /<title[^>]*>([\s\S]*?)<\/title>/i,
  ]).replace(/\s*:\s*Amazon\.com.*$/i, '');

  let brand = matchFirst(html, [
    /<a[^>]+id=["']bylineInfo["'][^>]*>([\s\S]*?)<\/a>/i,
    /<tr[^>]*>\s*<th[^>]*>\s*Brand\s*<\/th>\s*<td[^>]*>([\s\S]*?)<\/td>/i,
    /<span[^>]*>\s*Brand\s*<\/span>\s*<span[^>]*>([\s\S]*?)<\/span>/i,
  ]);
  brand = stripTags(brand).replace(/^Visit the\s+/i, '').replace(/\s+Store$/i, '');

  const price = matchFirst(html, [
    /<span[^>]+class=["'][^"']*a-price[^"']*["'][^>]*>[\s\S]*?<span[^>]+class=["']a-offscreen["'][^>]*>([^<]+)<\/span>/i,
    /<meta[^>]+name=["']twitter:data1["'][^>]+content=["']([^"']+)["']/i,
    /<span[^>]+id=["']priceblock_[^"']+["'][^>]*>([^<]+)<\/span>/i,
  ]);

  const rating = matchFirst(html, [
    /<span[^>]+class=["'][^"']*a-icon-alt[^"']*["'][^>]*>([0-9.]+\s*out of\s*5 stars)<\/span>/i,
    /([0-9.]+)\s*out of\s*5 stars/i,
  ]).replace(/\s*out of\s*5 stars/i, '');

  const reviewsText = matchFirst(html, [
    /<span[^>]+id=["']acrCustomerReviewText["'][^>]*>([^<]+)<\/span>/i,
    /([0-9,]+)\s+ratings?/i,
  ]);
  const reviews_count = parseInt(String(reviewsText).replace(/[^0-9]/g, ''), 10) || 0;

  const image_url = matchFirst(html, [
    /<img[^>]+id=["']landingImage["'][^>]+data-old-hires=["']([^"']+)["']/i,
    /<img[^>]+id=["']landingImage["'][^>]+src=["']([^"']+)["']/i,
    /<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i,
  ]);

  const bulletsBlock = matchFirst(html, [
    /<div[^>]+id=["']feature-bullets["'][^>]*>([\s\S]*?)<\/div>\s*<\/div>/i,
    /<ul[^>]+class=["'][^"']*a-unordered-list[^"']*a-vertical[^"']*a-spacing-mini[^"']*["'][^>]*>([\s\S]*?)<\/ul>/i,
  ]);
  const features_array = Array.from(String(bulletsBlock || '').matchAll(/<li[^>]*>([\s\S]*?)<\/li>/gi))
    .map(match => stripTags(match[1]))
    .filter(line => line && !/^make sure this fits/i.test(line))
    .slice(0, 12);

  const specs = [];
  for (const tableMatch of String(html || '').matchAll(/<tr[^>]*>\s*<(?:th|td)[^>]*>([\s\S]*?)<\/(?:th|td)>\s*<td[^>]*>([\s\S]*?)<\/td>\s*<\/tr>/gi)) {
    const name = stripTags(tableMatch[1]).replace(/:$/, '');
    const value = stripTags(tableMatch[2]);
    if (name && value && name.length < 80 && value.length < 300) specs.push({ name, value });
  }

  for (const bulletMatch of String(html || '').matchAll(/<li[^>]*>\s*<span[^>]*class=["'][^"']*a-list-item[^"']*["'][^>]*>\s*<span[^>]*>([\s\S]*?)<\/span>\s*<span[^>]*>([\s\S]*?)<\/span>/gi)) {
    const name = stripTags(bulletMatch[1]).replace(/:$/, '');
    const value = stripTags(bulletMatch[2]);
    if (name && value && name.length < 80 && value.length < 300) specs.push({ name, value });
  }

  const seenSpecs = new Set();
  const specifications_array = specs.filter(entry => {
    const key = entry.name.toLowerCase() + '=' + entry.value.toLowerCase();
    if (seenSpecs.has(key)) return false;
    seenSpecs.add(key);
    return true;
  }).slice(0, 80);

  const description = matchFirst(html, [
    /<div[^>]+id=["']productDescription["'][^>]*>([\s\S]*?)<\/div>/i,
    /<div[^>]+id=["']aplus["'][^>]*>([\s\S]*?)<\/div>/i,
  ]);

  return {
    asin,
    name: title,
    title,
    brand,
    pricing: price,
    average_rating: rating,
    total_reviews: reviews_count,
    image_url,
    description: compactText(stripTags(description), 4000),
    feature_bullets: features_array,
    product_information: {
      asin,
      brand_name: brand,
      customer_reviews: rating ? { stars: rating } : undefined,
