function cleanHtml(value) {
  return String(value ?? '')
    .replace(/\*\*/g, '')
    .replace(/^#+\s*/gm, '')
    .replace(/<([a-z0-9]+)(?:\s+[^>]*)?>/gi, (match, tag) => {
      const allowed = new Set(['p', 'ul', 'li', 'strong', 'em', 'br']);
      return allowed.has(String(tag).toLowerCase()) ? '<' + tag.toLowerCase() + '>' : '';
    })
    .replace(/<\/([a-z0-9]+)>/gi, (match, tag) => {
      const allowed = new Set(['p', 'ul', 'li', 'strong', 'em']);
      return allowed.has(String(tag).toLowerCase()) ? '</' + tag.toLowerCase() + '>' : '';
    })
    .trim();
}

