function titleCase(value) {
  const small = new Set(['a', 'an', 'and', 'as', 'at', 'but', 'by', 'for', 'from', 'in', 'into', 'nor', 'of', 'on', 'or', 'per', 'the', 'to', 'vs', 'via', 'with', 'without', 'under']);
  const acronyms = new Set(['ai', 'cpu', 'gpu', 'led', 'usb', 'us', 'usa', 'uk', 'pc', 'mac', 'wfh', 'xl', 'tkl']);
  return String(value || '').toLowerCase().split(/\s+/).filter(Boolean).map((word, index, arr) => {
    const plain = word.replace(/[^a-z0-9]/g, '');
    if (acronyms.has(plain)) return plain.toUpperCase();
    if (index > 0 && index < arr.length - 1 && small.has(plain)) return plain;
    return word.split('-').map(part => {
      const stripped = part.replace(/[^a-z0-9]/g, '');
      if (acronyms.has(stripped)) return stripped.toUpperCase();
      return part ? part.charAt(0).toUpperCase() + part.slice(1) : part;
    }).join('-');
  }).join(' ');
}

function topicWithoutBest(value) {
  return String(value || '')
    .replace(/^(best|top|good)\s+/i, '')
    .replace(/\s+/g, ' ')
