}

function cleanResearchIntent(value) {
  return String(value || '')
    .replace(/\b(reddit|wirecutter|quora|forum|forums|discussion|discussions)\b/gi, '')
    .replace(/\b(review|reviews|recommendation|recommendations|opinion|opinions)\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function searchIntent(value) {
  const text = String(value || '').toLowerCase();
  if (/\b(reddit|wirecutter|forum|forums|quora)\b/.test(text)) return 'validation';
  if (/\b(vs|versus|compare|comparison)\b/.test(text)) return 'comparison';
  if (/\b(cheap|budget|affordable)\b|\bunder\s+\$?\d{2,5}\b/.test(text)) return 'budget';
  if (/^how\s+to\b|\bhow do i\b|\bideas?\b|\bsetup\b/.test(text)) return 'guide';
  return 'commercial';
}

function reorderHomeOfficeTopic(value, categoryName) {
  const cleaned = cleanResearchIntent(value).toLowerCase();

  if (categoryName === 'Cable Management') {
    if (/\bunder\s+desk\b/.test(cleaned) && /\btray|trays|organizer|organizers|cord|cable\b/.test(cleaned)) return 'Under-Desk Cable Management Trays and Cord Organizers';
    if (/\bunder\s+desk\b/.test(cleaned)) return 'Under-Desk Cable Management';
    if (/\bstanding desk\b/.test(cleaned)) return 'Standing Desk Cable Management';
    if (/\bdesk\b/.test(cleaned)) return 'Desk Cable Management';
    if (/\bcord\b/.test(cleaned)) return 'Cord Management for Home Office Desks';
    return 'Cable Management for Home Office Desks';
  }

  if (categoryName === 'Desk Lighting' && /\bzoom|video|meeting|meetings\b/.test(cleaned)) {
    return 'Desk Lighting for Zoom Meetings';
  }

  if (categoryName === 'Monitor Arms' && /\bdual monitor|two monitors\b/.test(cleaned)) {
    return 'Monitor Arms for Dual Monitors';
  }

  if (categoryName === 'Footrests & Mats') {
    if (/\badjustable|height|under\s+desk|foot\s*rest|footrest\b/.test(cleaned)) return 'Adjustable Height Under-Desk Footrests';
    if (/\banti\s+fatigue|standing\s+mat|desk\s+mat\b/.test(cleaned)) return 'Anti-Fatigue Mats for Standing Desks';
    return 'Footrests and Mats for Home Office Comfort';
  }

  if (categoryName === 'Ergonomic Chairs' && /\bback pain\b/.test(cleaned)) {
    return 'Ergonomic Chairs for Back Pain';
  }

  return titleCase(cleanResearchIntent(value));
}

function budgetTopic(value, categoryName) {
  let cleaned = cleanResearchIntent(value)
    .replace(/^(best|top|cheap|budget|affordable)\s+/i, '')
    .replace(/\bunder\s+\$?\s*(\d{2,5})\b/i, 'under $$$1')
    .replace(/\s+/g, ' ')
    .trim();

  if (categoryName === 'Standing Desks') cleaned = cleaned.replace(/\bstanding desk\b/i, 'standing desks');
  if (categoryName === 'Ergonomic Chairs') cleaned = cleaned.replace(/\bergonomic chair\b/i, 'ergonomic chairs');
  if (categoryName === 'Monitor Arms') cleaned = cleaned.replace(/\bmonitor arm\b/i, 'monitor arms');

  return titleCase(cleaned || reorderHomeOfficeTopic(value, categoryName));
}

function hasSpecificModifier(value) {
  const text = cleanResearchIntent(value).toLowerCase();
  return (
    /\b(vs|versus|without|small|dual|standing desk|home office|back pain|gaming|programming|reading|zoom|video calls?|under desk|office chair)\b/.test(text) ||
    /\bunder\s+\$?\d{2,5}\b/.test(text) ||
    /\bfor\s+(back pain|dual monitors?|small spaces?|home office|standing desks?|reading|zoom|video calls?|gaming|programming)\b/.test(text) ||
    /\bwith\s+(drawers?|storage|keyboard tray|power outlets?|lights?|monitor stand|wheels?|arms?|headrest|lumbar support)\b/.test(text)
  );
}

function makeArticleTitle(value, categoryName) {
  const raw = String(value || '').trim();
  const lower = raw.toLowerCase();
  if (!raw) return 'Best Home Office Products Worth Shortlisting';
  const intent = searchIntent(raw);
  const topic = reorderHomeOfficeTopic(raw, categoryName);

  if (categoryName === 'Cable Management' && /\bunder\s+desk\b/.test(lower) && /\btray|trays|organizer|organizers|cord|cable\b/.test(lower)) {
    return 'Best Under-Desk Cable Management Trays and Cord Organizers';
  }

  if (intent === 'validation') {
    if (categoryName === 'Cable Management') {
      return `Best ${topic}: Trays, Clips, Sleeves, and Raceways Compared`;
    }
    return `Best ${topic}: What to Check Before You Buy`;
  }

  if (intent === 'comparison') {
    return `${topic}: Key Differences, Trade-Offs, and Better Picks`;
  }

  if (intent === 'budget') {
    return `Best ${budgetTopic(raw, categoryName)}: Affordable Picks That Still Make Sense`;
  }

  if (hasSpecificModifier(raw)) {
    if (/^best\s+/i.test(raw)) return titleCase(raw);
    return 'Best ' + topic + ' for Home Offices';
  }

  const broadTitleMap = {
    'Cable Management': 'Best Cord Management for Home Office Desks',
    'Desk Lighting': 'Best Desk Lighting for Home Offices',
    'Monitor Arms': 'Best Monitor Arms for Home Office Desks',
    'Desk Storage': 'Best Desk Storage Ideas and Organizers for Home Offices',
    'Desk Accessories': 'Best Desk Accessories for a Cleaner Home Office',
    'Footrests & Mats': 'Best Footrests and Mats for Home Office Comfort',
    'Desk Converters': 'Best Desk Converters for Home Office Workstations',
    'Standing Desks': 'Best Standing Desks for Home Offices',
    'Ergonomic Chairs': 'Best Ergonomic Chairs for Home Office Back Support',
    'Keyboards & Mice': 'Best Keyboards and Mice for Home Office Work',
    'Ergonomics & Health': 'Best Ergonomics Tips for a Healthier Home Office',
    'Workspace Ideas': 'Best Home Office Setup Ideas for Small and Shared Spaces',
    'Productivity': 'Best Work From Home Productivity Tips That Are Practical'
  };

  if (/^best\s+cord management$/i.test(raw)) return 'Best Cord Management for Home Office Desks';
  if (/^best\s+cable management$/i.test(raw)) return 'Best Cable Management for Home Office Desks';
  if (/^best\s+/.test(lower) && broadTitleMap[categoryName]) return broadTitleMap[categoryName];
  if (/^best\s+/.test(lower)) return titleCase(raw + ' for Home Offices');
  if (broadTitleMap[categoryName]) return broadTitleMap[categoryName];
  return titleCase(raw);
}

function categoryTopic(categoryName, title) {
