function estimateAiCost(modelName, tokenUsage) {
  const lower = String(modelName || '').toLowerCase();
  let inputPerMillion = 1;
  let outputPerMillion = 5;
  if (lower.includes('sonnet')) {
    inputPerMillion = 3;
    outputPerMillion = 15;
  } else if (lower.includes('haiku')) {
    inputPerMillion = 1;
    outputPerMillion = 5;
  } else if (lower.includes('gpt-4o-mini')) {
    inputPerMillion = 0.15;
    outputPerMillion = 0.6;
  } else if (lower.includes('gpt-4o')) {
    inputPerMillion = 2.5;
    outputPerMillion = 10;
  } else if (lower.includes('gemini')) {
    inputPerMillion = 0.35;
    outputPerMillion = 1.05;
  }
  const inputTokens = Number(tokenUsage.input_tokens || tokenUsage.prompt_tokens || 0);
  const outputTokens = Number(tokenUsage.output_tokens || tokenUsage.completion_tokens || 0);
  return Number(((inputTokens * inputPerMillion + outputTokens * outputPerMillion) / 1000000).toFixed(6));
}

function plainText(value) {
  return String(value || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#8217;|&rsquo;/g, "'")
    .replace(/&#8220;|&#8221;|&ldquo;|&rdquo;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

function truncateAtWord(value, max) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (text.length <= max) return text;
  const cut = text.slice(0, max - 1);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > 45 ? cut.slice(0, lastSpace) : cut).replace(/[,:;-]+$/g, '').trim();
}

function makeSeoTitle(title, focus) {
