function extractFaqSchema(html) {
  const faqStart = html.search(/<h2[^>]*>\s*FAQs?\s*<\/h2>/i);
  if (faqStart < 0) return null;
  const faqHtml = html.slice(faqStart);
  const pattern = /<h3[^>]*>([\s\S]*?)<\/h3>([\s\S]*?)(?=<h3[^>]*>|<h2[^>]*>|$)/gi;
  const entities = [];
  let match;
  while ((match = pattern.exec(faqHtml)) && entities.length < 5) {
    const question = plainText(match[1]);
    const answer = truncateAtWord(plainText(match[2]), 450);
    if (question && answer) {
      entities.push({
        '@type': 'Question',
        name: question,
        acceptedAnswer: {
          '@type': 'Answer',
          text: answer
        }
      });
    }
  }
  if (entities.length < 3) return null;
  return {
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    mainEntity: entities
  };
}

function countInternalLinks(html) {
  const links = Array.from(String(html || '').matchAll(/<a[^>]+href=["']([^"']+)["'][^>]*>/gi))
    .map(match => String(match[1] || '').trim())
    .filter(Boolean);
  const internal = links.filter(href => {
    if (/amazon\.com|amzn\.to/i.test(href)) return false;
    return href.startsWith('/') || /^https?:\/\/(www\.)?aurahomeoffice\.com\b/i.test(href);
  });
  return new Set(internal.map(href => href.replace(/^https?:\/\/(www\.)?aurahomeoffice\.com/i, '').replace(/[#?].*$/, '').replace(/\/$/, ''))).size;
}

