function normalizeAuraScore(...values) {
  for (const value of values) {
    if (value === undefined || value === null || value === '') continue;
    let score = Number(value);
    if (!Number.isFinite(score)) continue;
    if (score > 10 && score <= 100) score = score / 10;
    if (score > 0 && score <= 1) score = score * 10;
    return Math.max(0, Math.min(10, Math.round(score * 10) / 10));
  }
  return null;
}

function scoreLabel(score) {
  if (!Number.isFinite(score)) return '';
  if (score >= 9) return 'Gold Standard';
  if (score >= 7.5) return 'Recommended';
  if (score >= 6) return 'Functional';
  if (score >= 4) return 'Average';
  return 'Poor';
}

function specsFromString(value) {
  return String(value || '')
    .split(/\n+/)
    .map(line => {
      const idx = line.indexOf(':');
      if (idx < 0) return null;
      return {
        name: clean(line.slice(0, idx)),
        value: clean(line.slice(idx + 1))
      };
    })
    .filter(entry => entry && entry.name && entry.value);
}

function normalizeSpecs(value, fallbackText) {
  if (Array.isArray(value) && value.length) {
    return value
      .map(entry => ({
        name: clean(entry?.name || entry?.label || entry?.key),
        value: clean(entry?.value)
      }))
      .filter(entry => entry.name && entry.value);
  }
  return specsFromString(fallbackText);
}

