function clean(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function list(value) {
  return Array.isArray(value) ? value.filter(Boolean) : [];
}

function lines(value) {
  if (Array.isArray(value)) {
    return value.map(entry => {
      if (entry && typeof entry === 'object') {
        const name = clean(entry.name || entry.label || entry.key);
        const val = clean(entry.value || entry.text || entry.content);
        return [name, val].filter(Boolean).join(': ');
      }
      return clean(entry);
    }).filter(Boolean).join('\n');
  }
  return clean(value);
}

const cachedItems = checks.flatMap((item, index) => {
  const result = item.json || {};
  if (!result.exists || !result.has_custom_content || !result.product) return [];

  const split = splitItems[index]?.json || {};
  const product = result.product || {};
  const asin = clean(product.asin || result.asin || split.asins || split.asin);
  const featuresArray = list(product.features);
  const topReviewsArray = list(product.top_reviews);
  const specificationsText = lines(product.specifications);
  const featureText = lines(featuresArray);
  const topReviewsText = topReviewsArray.map(review => {
    if (review && typeof review === 'object') {
      return [review.title, review.rating, review.review || review.text || review.content].filter(Boolean).join('\n');
    }
    return clean(review);
  }).filter(Boolean).join('\n---\n');

  const review = {
    short_product_name: product.short_product_name || '',
    product_label: product.product_label || '',
    custom_title: clean(product.custom_title),
    short_review: clean(product.custom_description),
    evidence_basis: product.evidence_basis || 'Existing Aura product review content.',
    source_basis: 'existing product cache',
    claim_confidence: 'medium',
    score: product.score || null,
    score_label: product.score_label || '',
    score_rationale: product.score_rationale || '',
    missing_specs: [],
    selling_points: list(product.custom_features),
    pros: list(product.custom_pros),
    cons: list(product.custom_cons),
    custom_tabs: list(product.custom_tabs),
    comparison_summary: product.comparison_summary || {}
  };

  return [{
    json: {
      ...split,
      asin,
      asin_code: asin,
      status: 'success',
      _pipeline_status: 'success',
      _cache_hit: true,
      _skip_reason: 'existing_product_has_custom_content',
      title: clean(product.title),
      asin_title: clean(product.title),
      brand: clean(product.brand),
      asin_brand: clean(product.brand),
      rating: product.rating || '',
      reviews_count: product.reviews_count || 0,
      price: product.price || '',
      image_url: product.image_url || '',
      description: product.description || '',
      asin_description: product.description || '',
      features: featureText,
      asin_features: featureText,
      features_array: featuresArray,
      specifications: specificationsText,
      asin_specifications: product.specifications || [],
      specifications_array: product.specifications || [],
      top_reviews: topReviewsText,
      asin_top_reviews: topReviewsArray,
      top_reviews_array: topReviewsArray,
      review,
      ai_review: review,
      ai_output: review,
      ai_title: review.custom_title,
      ai_short_review: review.short_review,
      ai_pros: review.pros,
      ai_cons: review.cons,
      ai_tabs: review.custom_tabs,
      selling_points: review.selling_points,
      score: review.score,
      score_label: review.score_label,
      score_rationale: review.score_rationale,
      ai_usage: {},
      ai_model: 'existing-product-cache',
      ai_cost: 0,
      ai_cost_estimate: 0,
      ai_input_tokens: 0,
      ai_output_tokens: 0
    }
  }];
});

return cachedItems.length ? cachedItems : [{ json: { _merge_placeholder: true, _pipeline_status: 'placeholder', _cache_hit: false } }];

const checks = $input.all();
const splitItems = $('Split ASINs').all();

const refreshItems = checks.flatMap((item, index) => {
  const result = item.json || {};
  if (result.exists && result.has_custom_content && result.product) return [];

  const split = splitItems[index]?.json || {};
  return [{
    json: {
      ...split,
      existing_product_status: {
        exists: !!result.exists,
        has_custom_content: !!result.has_custom_content,
        asin: result.asin || split.asins || split.asin || ''
      }
    }
  }];
});

return refreshItems.length ? refreshItems : [{ json: { _no_refresh_needed: true, _merge_placeholder: true, _pipeline_status: 'placeholder' } }];
